/**
 * LayerInfinite MCP Server — rest-client.ts
 * ══════════════════════════════════════════════════════════════
 * V2 Gateway HTTP clients.
 *
 *   LiApiClient        — REST client for the LayerInfinite API
 *   UpstreamMCPClient  — MCP JSON-RPC proxy to upstream servers
 *
 * Production hardening:
 *   - Exponential backoff retry for transient failures (429, 502, 503, 504)
 *   - Circuit breaker integration via UpstreamRegistry + FailOpenState
 *   - Structured request/response logging
 *   - 15s LI API timeout, 30s MCP proxy timeout
 *   - Native fetch() + AbortController — zero external HTTP dependencies
 * ══════════════════════════════════════════════════════════════
 */

import type { GatewayConfig, UpstreamServer } from './config.js';
import type { ScoredAction, PolicyDecision, OutcomePayload } from './types.js';
import { logger } from './logger.js';
import { UpstreamRegistry } from './upstream-registry.js';
import {
  recordUpstreamFailure,
  recordUpstreamSuccess,
} from './fail-open.js';

// ── Shared types (preserved from V1 for backwards compatibility) ─

export interface LIApiError {
  error: string;
  code: string;
  message?: string;
  details?: unknown;
}

export interface LIApiResponse<T> {
  ok: true;
  status: number;
  data: T;
}

export interface LIApiErrorResponse {
  ok: false;
  status: number;
  error: LIApiError;
}

export type LIResult<T> = LIApiResponse<T> | LIApiErrorResponse;

// ── Upstream MCP proxy types ────────────────────────────────────

export interface RawUpstreamTool {
  name: string;
  description: string;
  inputSchema: Record<string, unknown>;
}

export interface UpstreamCallResult {
  content: Array<{ type: string; text?: string; [key: string]: unknown }>;
  isError?: boolean;
}

// ── Internal MCP request result ─────────────────────────────────

interface McpRequestResult<T> {
  ok: boolean;
  status: number;
  data?: T;
  error?: { code: string; message: string };
}

// ── Constants ───────────────────────────────────────────────────

const LI_TIMEOUT_MS = 15_000;
const MCP_TIMEOUT_MS = 30_000;
const RETRYABLE_STATUS_CODES: ReadonlySet<number> = new Set([429, 502, 503, 504]);
const MAX_RETRIES = 2;
const BASE_RETRY_DELAY_MS = 500;

function isRetryableStatus(status: number): boolean {
  return RETRYABLE_STATUS_CODES.has(status);
}

function isRetryableErrorCode(code: string): boolean {
  return code === 'TIMEOUT' || code === 'NETWORK_ERROR';
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Strip trailing slashes and whitespace from a URL.
 */
function cleanUrl(raw: string): string {
  return raw.replace(/\/+$/, '').trim();
}

// ═══════════════════════════════════════════════════════════════
// LiApiClient — REST client for the LayerInfinite API
// ═══════════════════════════════════════════════════════════════

export class LiApiClient {
  private readonly baseUrl: string;
  private readonly headers: Record<string, string>;
  private readonly log = logger.forTool('li-api-client');

  constructor(config: GatewayConfig) {
    this.baseUrl = cleanUrl(config.baseUrl);
    this.headers = {
      'X-API-Key': config.apiKey,
      'Content-Type': 'application/json',
      'User-Agent': '@layerinfinite/mcp-server/2.0.0',
    };
    this.log.info('LiApiClient initialized', { baseUrl: this.baseUrl });
  }

  /** Fetch scored actions for a task type from LI API. Returns [] on cold start. */
  async getScores(customerId: string, taskType: string): Promise<ScoredAction[]> {
    const result = await this.get<ScoredAction[]>('/v1/get-scores', {
      customer_id: customerId,
      task_type: taskType,
    });
    if (result.ok) return result.data;
    this.log.warn('getScores failed — returning empty array (cold start)', {
      customerId,
      taskType,
      status: result.status,
      code: result.error.code,
    });
    return [];
  }

  /** Get the current policy decision for a task type. */
  async getPolicyDecision(
    customerId: string,
    taskType: string,
  ): Promise<PolicyDecision | null> {
    const result = await this.get<PolicyDecision>('/v1/get-policy-decision', {
      customer_id: customerId,
      task_type: taskType,
    });
    if (result.ok) return result.data;
    this.log.warn('getPolicyDecision failed — returning null', {
      customerId,
      taskType,
      status: result.status,
      code: result.error.code,
    });
    return null;
  }

  /** Log an outcome payload to LI API. Returns true on success. */
  async logOutcome(payload: OutcomePayload): Promise<boolean> {
    const result = await this.post<{ success: boolean }>(
      '/v1/log-outcome',
      payload as unknown as Record<string, unknown>,
    );
    if (result.ok) return true;
    this.log.warn('logOutcome failed', {
      decisionId: payload.decision_id,
      actionName: payload.action_name,
      status: result.status,
      code: result.error.code,
    });
    return false;
  }

  /** Get ranked recommendations (for li_recommend tool). */
  async getRecommendations(
    taskType: string,
    customerId?: string,
  ): Promise<ScoredAction[]> {
    const params: Record<string, string> = { task_type: taskType };
    if (customerId) params.customer_id = customerId;
    const result = await this.get<ScoredAction[]>('/v1/get-scores', params);
    if (result.ok) return result.data;
    this.log.warn('getRecommendations failed — returning []', {
      taskType,
      customerId,
      status: result.status,
      code: result.error.code,
    });
    return [];
  }

  // ── Private HTTP helpers ────────────────────────────────────

  private async get<T>(
    path: string,
    params?: Record<string, string>,
  ): Promise<LIResult<T>> {
    const url = new URL(`${this.baseUrl}${path}`);
    if (params) {
      for (const [key, value] of Object.entries(params)) {
        if (value !== undefined && value !== '') {
          url.searchParams.set(key, value);
        }
      }
    }
    return this.requestWithRetry<T>(url.toString(), { method: 'GET' });
  }

  private async post<T>(
    path: string,
    body: Record<string, unknown>,
  ): Promise<LIResult<T>> {
    const url = `${this.baseUrl}${path}`;
    return this.requestWithRetry<T>(url, {
      method: 'POST',
      body: JSON.stringify(body),
    });
  }

  /**
   * Request with exponential backoff retry for transient failures.
   * Retries on: 429, 502, 503, 504, TIMEOUT, NETWORK_ERROR
   * Does NOT retry on: 400, 401, 403, 404 (client errors are permanent)
   */
  private async requestWithRetry<T>(
    url: string,
    init: RequestInit,
  ): Promise<LIResult<T>> {
    let lastResult: LIResult<T> | null = null;

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
      if (attempt > 0) {
        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
        this.log.warn('Retrying LI API request', {
          url,
          method: init.method,
          attempt: attempt + 1,
          delayMs: delay,
        });
        await sleep(delay);
      }

      const result = await this.fetchOne<T>(url, init);
      if (result.ok) return result;

      lastResult = result;
      if (!isRetryableStatus(result.status) && !isRetryableErrorCode(result.error.code)) {
        break;
      }
    }

    return lastResult!;
  }

  private async fetchOne<T>(
    url: string,
    init: RequestInit,
  ): Promise<LIResult<T>> {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), LI_TIMEOUT_MS);
    const startMs = Date.now();

    try {
      const response = await fetch(url, {
        ...init,
        headers: {
          ...this.headers,
          ...(init.headers as Record<string, string> ?? {}),
        },
        signal: controller.signal,
      });

      const latencyMs = Date.now() - startMs;
      const contentType = response.headers.get('content-type') ?? '';
      const isJson = contentType.includes('application/json');

      if (response.ok) {
        const data = isJson ? (await response.json()) as T : ({} as T);
        this.log.debug('LI API response', {
          method: init.method,
          url,
          status: response.status,
          latencyMs,
        });
        return { ok: true, status: response.status, data };
      }

      const errorBody = isJson
        ? (await response.json()) as LIApiError
        : {
            error: 'API Error',
            code: 'UNKNOWN',
            message: await response.text(),
          };

      this.log.warn('LI API error', {
        method: init.method,
        url,
        status: response.status,
        latencyMs,
        errorCode: errorBody.code,
      });

      return { ok: false, status: response.status, error: errorBody };
    } catch (err) {
      const latencyMs = Date.now() - startMs;

      if (err instanceof DOMException && err.name === 'AbortError') {
        this.log.error('LI API request timed out', {
          method: init.method,
          url,
          timeoutMs: LI_TIMEOUT_MS,
          latencyMs,
        });
        return {
          ok: false,
          status: 0,
          error: {
            error: 'Request timed out',
            code: 'TIMEOUT',
            message: `Request to ${url} timed out after ${LI_TIMEOUT_MS}ms`,
          },
        };
      }

      const message = err instanceof Error ? err.message : String(err);
      this.log.error('LI API network error', {
        method: init.method,
        url,
        latencyMs,
        error: message,
      });
      return {
        ok: false,
        status: 0,
        error: { error: 'Network error', code: 'NETWORK_ERROR', message },
      };
    } finally {
      clearTimeout(timer);
    }
  }
}

// ═══════════════════════════════════════════════════════════════
// UpstreamMCPClient — MCP JSON-RPC proxy to upstream servers
// ═══════════════════════════════════════════════════════════════

export class UpstreamMCPClient {
  private readonly registry: UpstreamRegistry;
  private readonly servers: ReadonlyMap<string, UpstreamServer>;
  private readonly log = logger.forTool('upstream-mcp-client');

  constructor(servers: readonly UpstreamServer[]) {
    // Construct minimal GatewayConfig — UpstreamRegistry only uses upstreamServers
    this.registry = new UpstreamRegistry({
      upstreamServers: servers,
    } as GatewayConfig);
    this.servers = new Map(servers.map((s) => [s.name, s]));
  }

  /** Fetch the full tool list from a single upstream MCP server via MCP protocol. */
  async listTools(upstreamName: string): Promise<RawUpstreamTool[]> {
    const server = this.servers.get(upstreamName);
    if (!server) {
      this.log.error('Unknown upstream — cannot list tools', { upstreamName });
      return [];
    }
    if (!this.registry.isHealthy(upstreamName)) {
      this.log.warn('Upstream unhealthy — cannot list tools', { upstreamName });
      return [];
    }

    const result = await this.sendMcpRequest<{ tools: RawUpstreamTool[] }>(
      server,
      'tools/list',
    );

    if (result.ok && result.data) {
      const tools = result.data.tools;
      if (Array.isArray(tools)) {
        return tools.map((t: Record<string, unknown>) => ({
          name: String(t.name ?? ''),
          description: String(t.description ?? ''),
          inputSchema: (t.inputSchema as Record<string, unknown>) ?? {},
        }));
      }
    }

    this.log.warn('listTools returned no tools', {
      upstreamName,
      ok: result.ok,
      error: result.error,
    });
    return [];
  }

  /** Call a tool on an upstream MCP server and get the result. */
  async callTool(
    upstreamName: string,
    toolName: string,
    args: Record<string, unknown>,
  ): Promise<UpstreamCallResult> {
    const server = this.servers.get(upstreamName);
    if (!server) {
      this.log.error('Unknown upstream — cannot call tool', { upstreamName, toolName });
      return { content: [], isError: true };
    }
    if (!this.registry.isHealthy(upstreamName)) {
      this.log.warn('Upstream unhealthy — cannot call tool', { upstreamName, toolName });
      return { content: [], isError: true };
    }

    const result = await this.sendMcpRequest<{
      content: Array<{ type: string; text?: string; [key: string]: unknown }>;
      isError?: boolean;
    }>(server, 'tools/call', { name: toolName, arguments: args });

    if (result.ok && result.data) {
      return {
        content: result.data.content ?? [],
        isError: result.data.isError ?? false,
      };
    }

    this.log.error('callTool failed', {
      upstreamName,
      toolName,
      status: result.status,
      error: result.error,
    });
    return {
      content: [
        {
          type: 'text',
          text: `Upstream tool call failed: ${result.error?.message ?? 'unknown error'}`,
        },
      ],
      isError: true,
    };
  }

  /** Return names of all currently healthy upstreams. */
  getHealthyUpstreams(): string[] {
    return Array.from(this.servers.keys()).filter((name) =>
      this.registry.isHealthy(name),
    );
  }

  /** Start health checks on all upstreams (delegates to UpstreamRegistry). */
  startHealthChecks(): void {
    this.registry.startHealthChecks();
    this.log.info('Upstream health checks started');
  }

  /** Stop health checks on all upstreams (delegates to UpstreamRegistry). */
  stopHealthChecks(): void {
    this.registry.stopHealthChecks();
    this.log.info('Upstream health checks stopped');
  }

  // ── Private MCP protocol helpers ─────────────────────────────

  /**
   * Send a JSON-RPC request to an upstream MCP server with retry.
   * id is deterministic: 1 for tools/list, 2 for tools/call.
   */
  private async sendMcpRequest<T>(
    server: UpstreamServer,
    method: string,
    params?: Record<string, unknown>,
  ): Promise<McpRequestResult<T>> {
    const url = `${cleanUrl(server.url)}/mcp`;
    const id = method === 'tools/list' ? 1 : 2;
    const body: Record<string, unknown> = { jsonrpc: '2.0', method, id };
    if (params) body.params = params;

    let lastResult: McpRequestResult<T> | null = null;

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
      if (attempt > 0) {
        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
        this.log.warn('Retrying MCP request', {
          upstream: server.name,
          method,
          attempt: attempt + 1,
          delayMs: delay,
        });
        await sleep(delay);
      }

      const result = await this.execMcpFetch<T>(server.name, url, server.apiKey, body);

      if (result.ok) {
        recordUpstreamSuccess(this.registry.getFailOpenState(), server.name);
        return result;
      }

      lastResult = result;
      recordUpstreamFailure(this.registry.getFailOpenState(), server.name);

      if (
        !isRetryableStatus(result.status) &&
        !isRetryableErrorCode(result.error?.code ?? '')
      ) {
        break;
      }
    }

    return lastResult!;
  }

  private async execMcpFetch<T>(
    upstreamName: string,
    url: string,
    apiKey: string | undefined,
    body: Record<string, unknown>,
  ): Promise<McpRequestResult<T>> {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), MCP_TIMEOUT_MS);
    const startMs = Date.now();

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'User-Agent': '@layerinfinite/mcp-server/2.0.0',
    };
    if (apiKey) headers['Authorization'] = `Bearer ${apiKey}`;

    try {
      const response = await fetch(url, {
        method: 'POST',
        headers,
        body: JSON.stringify(body),
        signal: controller.signal,
      });

      const latencyMs = Date.now() - startMs;
      const contentType = response.headers.get('content-type') ?? '';

      // Guard against non-JSON responses from upstream
      if (!contentType.includes('application/json')) {
        const text = await response.text();
        this.log.error('MCP upstream returned non-JSON', {
          upstream: upstreamName,
          url,
          status: response.status,
          latencyMs,
          contentType,
          bodyPreview: text.slice(0, 200),
        });
        return {
          ok: false,
          status: response.status,
          error: {
            code: 'NON_JSON_RESPONSE',
            message: `Upstream returned ${contentType || 'unknown content type'}`,
          },
        };
      }

      const json = (await response.json()) as Record<string, unknown>;

      if (response.ok) {
        // MCP JSON-RPC error: success at HTTP level but error at RPC level
        if (json.error) {
          const err = json.error as Record<string, unknown>;
          this.log.warn('MCP JSON-RPC error response', {
            upstream: upstreamName,
            method: body.method,
            latencyMs,
            rpcCode: err.code,
            rpcMessage: err.message,
          });
          return {
            ok: false,
            status: response.status,
            error: {
              code: String(err.code ?? 'MCP_RPC_ERROR'),
              message: String(err.message ?? 'Unknown MCP RPC error'),
            },
          };
        }

        this.log.debug('MCP response OK', {
          upstream: upstreamName,
          method: body.method,
          latencyMs,
        });
        return {
          ok: true,
          status: response.status,
          data: json.result as T,
        };
      }

      // HTTP-level error from upstream
      this.log.warn('MCP upstream HTTP error', {
        upstream: upstreamName,
        method: body.method,
        status: response.status,
        latencyMs,
      });
      return {
        ok: false,
        status: response.status,
        error: {
          code: 'UPSTREAM_HTTP_ERROR',
          message: `Upstream returned HTTP ${response.status}`,
        },
      };
    } catch (err) {
      const latencyMs = Date.now() - startMs;

      if (err instanceof DOMException && err.name === 'AbortError') {
        this.log.error('MCP request timed out', {
          upstream: upstreamName,
          url,
          method: body.method,
          timeoutMs: MCP_TIMEOUT_MS,
          latencyMs,
        });
        return {
          ok: false,
          status: 0,
          error: {
            code: 'TIMEOUT',
            message: `MCP request to ${url} timed out after ${MCP_TIMEOUT_MS}ms`,
          },
        };
      }

      const message = err instanceof Error ? err.message : String(err);
      this.log.error('MCP network error', {
        upstream: upstreamName,
        url,
        method: body.method,
        latencyMs,
        error: message,
      });
      return {
        ok: false,
        status: 0,
        error: { code: 'NETWORK_ERROR', message },
      };
    } finally {
      clearTimeout(timer);
    }
  }
}
